function runningMax(a) {
  const out = [];
  let best = -Infinity;
  for (let i = 0; i < a.length; i++) {
    if (a[i] > best) best = a[i];
    out.push(best);
  }
  return out;
}

tests:
if (JSON.stringify(runningMax([])) !== JSON.stringify([])) throw new Error('empty');
if (JSON.stringify(runningMax([3, 1, 4, 1, 5, 9, 2])) !== JSON.stringify([3, 3, 4, 4, 5, 9, 9])) throw new Error('rmax');
if (JSON.stringify(runningMax([-2, -5, -1])) !== JSON.stringify([-2, -2, -1])) throw new Error('neg');

