function countVowels(s) {
  let c = 0;
  for (let i = 0; i < s.length; i++) if ('aeiou'.includes(s[i])) c++;
  return c;
}

tests:
if (countVowels('') !== 0) throw new Error('empty');
if (countVowels('hello') !== 2) throw new Error('hello');
if (countVowels('xyz') !== 0) throw new Error('none');
if (countVowels('aeiou') !== 5) throw new Error('all');

