solution:
function closest(a, t) {
  let best = a[0];
  for (let i = 1; i < a.length; i++) if (Math.abs(a[i] - t) < Math.abs(best - t)) best = a[i];
  return best;
}

tests:
if (closest([5], 0) !== 5) throw new Error('single');
if (closest([10, 4, 7, 1], 5) !== 4) throw new Error('mix');
if (closest([-3, -1, -8], -2) !== -3) throw new Error('neg tie-first');

