function maxRise(a) {
  let best = 0;
  for (let i = 1; i < a.length; i++) {
    const d = a[i] - a[i - 1];
    if (d > best) best = d;
  }
  return best;
}

tests:
if (maxRise([]) !== 0) throw new Error('empty');
if (maxRise([5]) !== 0) throw new Error('single');
if (maxRise([1, 5, 2, 10]) !== 8) throw new Error('rise');
if (maxRise([5, 4, 3]) !== 0) throw new Error('descending');

