function reverseInPlace(a) {
  let lo = 0, hi = a.length - 1;
  while (lo < hi) {
    const t = a[lo];
    a[lo] = a[hi];
    a[hi] = t;
    lo++;
    hi--;
  }
  return a;
}

tests:
if (JSON.stringify(reverseInPlace([])) !== JSON.stringify([])) throw new Error('empty');
if (JSON.stringify(reverseInPlace([7])) !== JSON.stringify([7])) throw new Error('single');
if (JSON.stringify(reverseInPlace([1, 2, 3, 4])) !== JSON.stringify([4, 3, 2, 1])) throw new Error('even');
if (JSON.stringify(reverseInPlace([1, 2, 3])) !== JSON.stringify([3, 2, 1])) throw new Error('odd');
